// Pieuvre2026(v12) — assemble le 1er prospect seed à insérer
// Reçoit en input le driver courant + (places scrapées OU fallback log) selon la branche
const driver = $('Pour chaque driver').item.json;

let place = null;
let source = 'apify_google_maps';

// Tente l'Apify d'abord
try {
  const apifyOut = $('Apify Google Maps (3km)').first()?.json;
  if (Array.isArray(apifyOut) && apifyOut.length) {
    place = apifyOut[Math.floor(Math.random() * Math.min(apifyOut.length, 5))];
  } else if (apifyOut && Array.isArray(apifyOut.items) && apifyOut.items.length) {
    place = apifyOut.items[0];
  }
} catch (e) {}

// Sinon fallback hunter log
if (!place) {
  try {
    const fallback = $('Fallback hunter log proche').first()?.json;
    if (Array.isArray(fallback) && fallback.length) {
      const f = fallback[0];
      return [{ json: {
        driver_id: driver.driver_id,
        business_name: f.business_name,
        business_address: f.business_address,
        business_lat: f.business_lat,
        business_lng: f.business_lng,
        business_type: f.business_type || 'restaurant',
        contact_name: f.contact_name,
        contact_phone: f.contact_phone,
        contact_email: f.contact_email,
        status: 'seed',
        meta: { seed_source: 'fallback_hunter_log', warm_up: true, original_id: f.id },
        detected_at: new Date().toISOString(),
      }}];
    }
  } catch (e) {}
}

if (!place) {
  return []; // Rien à seed pour ce driver — boucle suivante
}

// Place Apify → row hunter log
const row = {
  driver_id: driver.driver_id,
  business_name: place.title || place.name || 'Établissement local',
  business_address: place.address || place.location?.address || null,
  business_lat: place.location?.lat || place.coordinates?.lat || null,
  business_lng: place.location?.lng || place.coordinates?.lng || null,
  business_type: place.category || place.categoryName || 'restaurant',
  contact_phone: place.phone || place.phoneNumber || null,
  contact_email: place.email || null,
  status: 'seed',
  meta: { seed_source: source, place_id: place.placeId || place.id, raw: place },
  detected_at: new Date().toISOString(),
};
return [{ json: row }];
